Create src/lib/supabase.js:

  import { createClient } from '@supabase/supabase-js';

  const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
  const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error('Missing Supabase env vars: VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY must be set');
  }

  export const supabase = createClient(supabaseUrl, supabaseAnonKey);

This is the sole place the client is instantiated. All other modules import { supabase } from './supabase.js'.

In supabase/migrations/20260529000000_initial_schema.sql, first section:

  CREATE TABLE IF NOT EXISTS public.profiles (
    id        uuid        PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    created_at timestamptz NOT NULL DEFAULT now(),
    show_count int2        NOT NULL DEFAULT 1
  );

  ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;

  CREATE POLICY "profiles_select" ON public.profiles
    FOR SELECT USING (id = auth.uid());

  CREATE POLICY "profiles_insert" ON public.profiles
    FOR INSERT WITH CHECK (id = auth.uid());

  CREATE POLICY "profiles_update" ON public.profiles
    FOR UPDATE USING (id = auth.uid()) WITH CHECK (id = auth.uid());

  CREATE POLICY "profiles_delete" ON public.profiles
    FOR DELETE USING (id = auth.uid());

Note: profiles uses id = auth.uid() (not user_id) because the PK is the user's own ID.

